INSERT INTO lessons (phase, section_id, section_name, lesson_number, lesson_title, tone, lesson_summary, read_block, systems_lesson, mini_framework, think_prompts, think_reflection, mission_drill, echelon_opening, echelon_closing, fog_level, story_beat, mission_badge_description, field_guide_prompt) VALUES

-- Lesson 1
('Design', 1, 'Perception Trinity', 1, 'VANGUARD UPLOAD 01: LATENCY', 'The first skill of future stewardship: accelerating response time without losing clarity.', 'Briefing Tone:<br/>"Every future system—human, machine, or hybrid—fails when response time slips below critical thresholds.<br/>Latency is the first enemy of aligned, intelligent systems.<br/>Your training begins with learning to detect it."', 'Mr White and Mrs. White, and their grown son, Herbert, are visited by Sergeant-Major Morris, a friend who served with the British Army in India. During dinner, he introduces them to a mummified monkey''s paw. He explains how an old fakir has placed a spell on the paw, so that it will grant three wishes but only with hellish consequences as punishment for tampering with fate. Morris, having had a horrible experience using the paw, throws it into the fire, but the sceptical Mr. White retrieves it. Before leaving, Morris warns Mr. White of what might happen should he use the paw.<br/><br/>Mr. White hesitates at first, believing that he already has everything he wants. At Herbert''s suggestion, Mr. White flippantly wishes for £200, which will enable him to make the final mortgage payment for his house; he then drops the paw, saying it moved and twisted like a snake. The following day, Herbert leaves for work. That night, a representative of Herbert''s employer arrives at the Whites'' home, telling them that Herbert has been killed in a terrible accident that mutilated his body. The company denies any responsibility, but tenders a bereavement payment to the family of £200.<br/><br/>A week after the funeral, Mrs. White, mad with grief, insists that her husband use the paw to wish Herbert back to life. Reluctantly, he does so, despite great unease at the thought of summoning his son''s mutilated and decomposing body. Later that night, there is a knock at the door. As Mrs. White fumbles at the locks in a desperate attempt to open the door, Mr. White becomes terrified and fears that the thing outside is not the son he loved. He makes his third and final wish. The knocking stops, and Mrs. White opens the door to find that no one is there.', 'The problem wasn''t the wish.<br/>The problem was the response time.<br/><br/>By the time the system responded, the world that made the request had changed.<br/><br/>That''s latency:<br/>when a system answers too late to matter — or too late to prevent harm.<br/><br/>Every future system—human, machine, or hybrid—fails when response time slips below critical thresholds.<br/>Latency is the first enemy of aligned, intelligent systems.', 'Mini-Framework — The Monkey''s Paw Rule<br/><br/>Before making a decision, ask three questions:<br/><br/>What might this solve?<br/><br/>What might this break?<br/><br/>Who might this harm?<br/><br/>If you cannot answer all three, you''re wishing — not leading.', 'Concept:<br/>"Latency is the silent decay of leadership systems.<br/>It erodes trust.<br/>It slows collaboration.<br/>It introduces risk.<br/>In a decentralized future, low-latency leaders keep systems safe."<br/>Reflection:<br/>"What leadership delay has caused friction in your life or team?"', '"What leadership delay has caused friction in your life or team?"', 'MISSION DRILL: TRACE THE DRAG<br/>You have 5 minutes.<br/>Step 1 — Identify a recent moment<br/>When someone waited on you<br/>or<br/>you waited on someone else.<br/>Step 2 — Draw the Latency Path<br/>Signal → Waiting → Response → Impact<br/>Step 3 — Circle the "drag point."<br/>The part that broke flow.<br/>Step 4 — Reduce it by one degree.<br/>Ask:<br/>"What is ONE thing I could remove, clarify, or shorten?"<br/>Completion Badge:<br/>"Latency Hunter — Level 1', 'Recruit, listen closely. You sense a strange latency ripple—Echelon confirms you felt something others cannot. I''m detecting Fog Level 1, which means environmental stability is deteriorating faster than projected. Anomaly Detected — Low-Level Latency Distortion. This situation requires your full attention and your unique perceptual strengths. Stay present — you and I will navigate this anomaly together.', 'This concludes your current sequence, Recruit. You sense a strange latency ripple—Echelon confirms you felt something others cannot. Fog Level 1 remains active — proceed with heightened awareness. Anomaly Detected — Low-Level Latency Distortion. Log your insight in your Field Guide. I''ll standby and monitor conditions until you are ready for the next upload.', 1, 'You sense a strange latency ripple—Echelon confirms you felt something others cannot.', 'You perceive early signals before others detect change. You sense shifts at the edge of systems and act before tension breaks.', 'Your daily mission:<br/>Name one problem you care about.');